/**
 * Complete runnable Java program demonstrating standard 1D Array operations
 * including insertion, traversal, search, and deletion.
 */
public class Main {
    public static void main(String[] args) {
        System.out.println("--- 1D Array Demonstration Program ---");

        // 1. Initialization: Create an array of capacity 10
        int[] numbers = new int[10];
        int currentSize = 0;

        // 2. Insertion: Adding elements to the array
        numbers[0] = 15;
        numbers[1] = 30;
        numbers[2] = 45;
        numbers[3] = 60;
        numbers[4] = 75;
        currentSize = 5;

        System.out.print("Initial Array Elements: ");
        printArray(numbers, currentSize);

        // 3. Search Operation: Looking for value 45
        int target = 45;
        int searchIndex = -1;
        for (int i = 0; i < currentSize; i++) {
            if (numbers[i] == target) {
                searchIndex = i;
                break;
            }
        }
        System.out.println("Searching for " + target + "... Found at index: " + searchIndex);

        // 4. Arbitrary Insertion: Insert 50 at index 3 (requires shifting)
        int insertIndex = 3;
        int newValue = 50;
        System.out.println("Inserting " + newValue + " at index " + insertIndex);

        // Shift elements to the right to make room
        for (int i = currentSize; i > insertIndex; i--) {
            numbers[i] = numbers[i - 1];
        }
        numbers[insertIndex] = newValue;
        currentSize++;

        System.out.print("Array after insertion: ");
        printArray(numbers, currentSize);

        // 5. Deletion Operation: Remove element at index 2 (value 45)
        int deleteIndex = 2;
        System.out.println("Deleting element at index " + deleteIndex);

        // Shift elements to the left to close the gap
        for (int i = deleteIndex; i < currentSize - 1; i++) {
            numbers[i] = numbers[i + 1];
        }
        numbers[currentSize - 1] = 0; // Clear last element slot
        currentSize--;

        System.out.print("Array after deletion: ");
        printArray(numbers, currentSize);
    }

    /**
     * Utility method to print the active elements of the array.
     */
    private static void printArray(int[] arr, int size) {
        System.out.print("[");
        for (int i = 0; i < size; i++) {
            System.out.print(arr[i]);
            if (i < size - 1) {
                System.out.print(", ");
            }
        }
        System.out.println("]");
    }
}

