        // 1. Initialization of a 3x4 uniform rectangular matrix
        int rows = 3;
        int columns = 4;
        int[][] matrix = new int[rows][columns];

        // 2. Populating the matrix with distinct values using nested loops
        int valueCounter = 10;
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < columns; j++) {
                matrix[i][j] = valueCounter;
                valueCounter += 5;
            }
        }

        System.out.println("Initial Matrix Grid Content:");
        displayMatrix(matrix);

        // 3. Directly accessing a specific coordinate cell
        int targetRow = 1;
        int targetCol = 2;
        System.out.println("Value located at position [" + targetRow + "][" + targetCol + "]: " + matrix[targetRow][targetCol]);

        // 4. Modifying data at an explicit coordinate
        System.out.println("Updating value at index [1][2] to 99...");
        matrix[targetRow][targetCol] = 99;

        // 5. Searching for an element inside the 2D matrix
        int searchTarget = 40;
        boolean found = false;
        int foundRow = -1, foundCol = -1;

        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[i].length; j++) {
                if (matrix[i][j] == searchTarget) {
                    found = true;
                    foundRow = i;
                    foundCol = j;
                    break;
                }
            }
            if (found) break;
        }

        if (found) {
            System.out.println("Target element " + searchTarget + " located at row " + foundRow + ", column " + foundCol);
        } else {
            System.out.println("Target element " + searchTarget + " was not found in the matrix grid.");
        }

        System.out.println("Final Matrix State:");
        displayMatrix(matrix);
    }

    /**
     * Utility method to print a 2D array matrix in a structured layout.
     */
    private static void displayMatrix(int[][] grid) {
        for (int i = 0; i < grid.length; i++) {
            System.out.print("  Row " + i + ": ");
            for (int j = 0; j < grid[i].length; j++) {
                System.out.print(grid[i][j] + "\t");
            }
            System.out.println();
        }
    }
}

