/**
 * Complete runnable Java program implementing a Singly Linked List
 * with core insertion, deletion, display, and traversal methods.
 */
public class Main {

    // Node structure representing a single link in the chain
    static class Node {
        int data;
        Node next;

        Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    private Node head = null;

    /**
     * Inserts a new node at the front of the list.
     */
    public void insertAtHead(int data) {
        Node newNode = new Node(data);
        newNode.next = head;
        head = newNode;
        System.out.println("Inserted " + data + " at the head.");
    }

    /**
     * Inserts a new node at the end of the list.
     */
    public void insertAtTail(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
            return;
        }
        Node temp = head;
        while (temp.next != null) {
            temp = temp.next;
        }
        temp.next = newNode;
        System.out.println("Inserted " + data + " at the tail.");
    }

    /**
     * Deletes the first occurrence of a specific value from the list.
     */
    public void deleteValue(int key) {
        Node temp = head, prev = null;

        // Case 1: Head itself holds the key
        if (temp != null && temp.data == key) {
            head = temp.next;
            System.out.println("Deleted value " + key + " from the list.");
            return;
        }

        // Case 2: Search for key while keeping track of previous node
        while (temp != null && temp.data != key) {
            prev = temp;
            temp = temp.next;
        }

        // Case 3: Key was not present in the list
        if (temp == null) {
            System.out.println("Value " + key + " not found in the list.");
            return;
        }

        // Unlink the node from the chain
        prev.next = temp.next;
        System.out.println("Deleted value " + key + " from the list.");
    }

    /**
     * Displays the full contents of the singly linked list.
     */
    public void printList() {
        Node current = head;
        System.out.print("List State: ");
        if (current == null) {
            System.out.println("Empty");
            return;
        }
        while (current != null) {
            System.out.print(current.data + " -> ");
            current = current.next;
        }
        System.out.println("null");
    }

    public static void main(String[] args) {
        System.out.println("--- Singly Linked List Demonstration ---");
        Main list = new Main();

        list.insertAtHead(20);
        list.insertAtHead(10);
        list.insertAtTail(30);
        list.insertAtTail(40);

        list.printList();

        list.deleteValue(30);
        list.printList();

        list.deleteValue(10);
        list.printList();
    }
}

