/**
 * Complete runnable Java program demonstrating a Doubly Linked List
 * with bidirectional insertion, traversal, and standard node removal.
 */
public class Main {

    // Node structure with forward and backward reference tracking links
    static class Node {
        int data;
        Node next;
        Node prev;

        Node(int data) {
            this.data = data;
            this.next = null;
            this.prev = null;
        }
    }

    private Node head = null;
    private Node tail = null;

    /**
     * Inserts a node at the front of the doubly linked list.
     */
    public void insertAtHead(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
            tail = newNode;
        } else {
            newNode.next = head;
            head.prev = newNode;
            head = newNode;
        }
        System.out.println("Inserted " + data + " at head.");
    }

    /**
     * Inserts a node at the end of the doubly linked list.
     */
    public void insertAtTail(int data) {
        Node newNode = new Node(data);
        if (tail == null) {
            head = newNode;
            tail = newNode;
        } else {
            tail.next = newNode;
            newNode.prev = tail;
            tail = newNode;
        }
        System.out.println("Inserted " + data + " at tail.");
    }

    /**
     * Deletes a specific node from the list.
     */
    public void deleteNode(int key) {
        Node current = head;

        // Traverse to locate target node
        while (current != null && current.data != key) {
            current = current.next;
        }

        if (current == null) {
            System.out.println("Value " + key + " not found for deletion.");
            return;
        }

        // Node found, adjust pointer links
        if (current == head) {
            head = current.next;
            if (head != null) head.prev = null;
        } else {
            current.prev.next = current.next;
        }

        if (current == tail) {
            tail = current.prev;
            if (tail != null) tail.next = null;
        } else {
            current.next.prev = current.prev;
        }

        System.out.println("Successfully deleted node containing: " + key);
    }

    /**
     * Prints list elements from Head forward.
     */
    public void printForward() {
        System.out.print("Forward Display: ");
        Node current = head;
        while (current != null) {
            System.out.print(current.data + " <-> ");
            current = current.next;
        }
        System.out.println("null");
    }

    /**
     * Prints list elements from Tail backward.
     */
    public void printBackward() {
        System.out.print("Backward Display: ");
        Node current = tail;
        while (current != null) {
            System.out.print(current.data + " <-> ");
            current = current.prev;
        }
        System.out.println("null");
    }

    public static void main(String[] args) {
        System.out.println("--- Doubly Linked List Demonstration ---");
        Main dList = new Main();

        dList.insertAtHead(50);
        dList.insertAtHead(40);
        dList.insertAtTail(60);
        dList.insertAtTail(70);

        dList.printForward();
        dList.printBackward();

        dList.deleteNode(60);
        dList.printForward();
    }
}

