/**
 * Complete runnable Java program implementing a Circular Linked List
 * managed via a Tail pointer, showing cyclic insertion, deletion, and display.
 */
public class Main {

    // Node structure with a single link field forming a loop
    static class Node {
        int data;
        Node next;

        Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    // Tracking via tail gives instant access to head (tail.next) and tail
    private Node tail = null;

    /**
     * Inserts a value at the beginning of the circular list.
     */
    public void insertAtHead(int data) {
        Node newNode = new Node(data);
        if (tail == null) {
            tail = newNode;
            newNode.next = newNode;
        } else {
            newNode.next = tail.next;
            tail.next = newNode;
        }
        System.out.println("Inserted " + data + " at head loop.");
    }

    /**
     * Inserts a value at the end of the circular list.
     */
    public void insertAtTail(int data) {
        Node newNode = new Node(data);
        if (tail == null) {
            tail = newNode;
            newNode.next = newNode;
        } else {
            newNode.next = tail.next;
            tail.next = newNode;
            tail = newNode;
        }
        System.out.println("Inserted " + data + " at tail loop.");
    }

    /**
     * Deletes a node with the specified value from the circular ring.
     */
    public void deleteValue(int key) {
        if (tail == null) {
            System.out.println("List is empty, deletion aborted.");
            return;
        }

        Node current = tail.next;
        Node prev = tail;
        boolean found = false;

        // Loop to find the target node
        do {
            if (current.data == key) {
                found = true;
                break;
            }
            prev = current;
            current = current.next;
        } while (current != tail.next);

        if (!found) {
            System.out.println("Element " + key + " not found in ring.");
            return;
        }

        // Case 1: Only one node in the list
        if (current == prev) {
            tail = null;
        } else {
            prev.next = current.next;
            // Adjust tail pointer if tail node is removed
            if (current == tail) {
                tail = prev;
            }
        }
        System.out.println("Deleted node containing " + key + " from circular list.");
    }

    /**
     * Traverses and displays the circular list without causing an infinite loop.
     */
    public void printList() {
        System.out.print("Circular List Content: ");
        if (tail == null) {
            System.out.println("Empty Ring");
            return;
        }
        Node current = tail.next;
        do {
            System.out.print(current.data + " -> ");
            current = current.next;
        } while (current != tail.next);
        System.out.println("(Loops back to " + tail.next.data + ")");
    }

    public static void main(String[] args) {
        System.out.println("--- Circular Linked List Demonstration ---");
        Main cList = new Main();

        cList.insertAtHead(100);
        cList.insertAtHead(90);
        cList.insertAtTail(110);
        cList.insertAtTail(120);

        cList.printList();

        cList.deleteValue(110);
        cList.printList();

        cList.deleteValue(90);
        cList.printList();
    }
}

