/**
 * Complete runnable Java program implementing a Circular Doubly Linked List.
 * Demonstrates bidirectional closed-loop insertion, removal, and traversal.
 */
public class Main {

    // Node structure with forward and backward circular reference links
    static class Node {
        int data;
        Node next;
        Node prev;

        Node(int data) {
            this.data = data;
            this.next = null;
            this.prev = null;
        }
    }

    private Node head = null;

    /**
     * Inserts a node at the head of the circular doubly linked list.
     */
    public void insertAtHead(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
            newNode.next = newNode;
            newNode.prev = newNode;
        } else {
            Node tail = head.prev;

            newNode.next = head;
            head.prev = newNode;
            newNode.prev = tail;
            tail.next = newNode;

            head = newNode;
        }
        System.out.println("Inserted " + data + " at circular head.");
    }

    /**
     * Inserts a node at the tail of the circular doubly linked list.
     */
    public void insertAtTail(int data) {
        Node newNode = new Node(data);
        if (head == null) {
            head = newNode;
            newNode.next = newNode;
            newNode.prev = newNode;
        } else {
            Node tail = head.prev;

            tail.next = newNode;
            newNode.prev = tail;
            newNode.next = head;
            head.prev = newNode;
        }
        System.out.println("Inserted " + data + " at circular tail.");
    }

    /**
     * Deletes a specific node from the circular closed loop.
     */
    public void deleteValue(int key) {
        if (head == null) {
            System.out.println("List empty, deletion aborted.");
            return;
        }

        Node current = head;
        boolean found = false;

        // Locate the target node
        do {
            if (current.data == key) {
                found = true;
                break;
            }
            current = current.next;
        } while (current != head);

        if (!found) {
            System.out.println("Value " + key + " not found in circular loop.");
            return;
        }

        // Adjust links for deletion
        if (current == head && current.next == head) {
            // Only one node in the list
            head = null;
        } else {
            current.prev.next = current.next;
            current.next.prev = current.prev;
            if (current == head) {
                head = current.next;
            }
        }
        System.out.println("Deleted value " + key + " from circular double loop.");
    }

    /**
     * Traverses the circular doubly list in a forward direction.
     */
    public void printForward() {
        System.out.print("Forward Ring: ");
        if (head == null) {
            System.out.println("Empty");
            return;
        }
        Node current = head;
        do {
            System.out.print(current.data + " <-> ");
            current = current.next;
        } while (current != head);
        System.out.println("(Loops back to Head)");
    }

    public static void main(String[] args) {
        System.out.println("--- Circular Doubly Linked List Demonstration ---");
        Main cdList = new Main();

        cdList.insertAtHead(500);
        cdList.insertAtHead(400);
        cdList.insertAtTail(600);
        cdList.insertAtTail(700);

        cdList.printForward();

        cdList.deleteValue(600); 
        cdList.printForward();

        cdList.deleteValue(400);
        cdList.printForward();
    }
}

