/**
 * Complete runnable Java program implementing a Stack using a fixed-size Array.
 * Includes overflow and underflow prevention safeguards.
 */
public class Main {
    private int maxSize;
    private int[] stackArray;
    private int top;

    // Constructor to initialize the stack with a fixed capacity
    public Main(int size) {
        this.maxSize = size;
        this.stackArray = new int[maxSize];
        this.top = -1; // -1 signifies that the stack is currently empty
    }

    /**
     * Pushes an element onto the top of the stack.
     */
    public void push(int value) {
        if (isFull()) {
            System.out.println("Stack Overflow! Cannot push " + value + " onto a full stack.");
            return;
        }
        stackArray[++top] = value;
        System.out.println("Pushed " + value + " onto the stack.");
    }

    /**
     * Pops and returns the top element off the stack.
     */
    public int pop() {
        if (isEmpty()) {
            System.out.println("Stack Underflow! Cannot pop from an empty stack.");
            return -1;
        }
        int poppedValue = stackArray[top--];
        return poppedValue;
    }

    /**
     * Peeks at the top element without removing it.
     */
    public int peek() {
        if (isEmpty()) {
            System.out.println("Stack is empty! Nothing to peek.");
            return -1;
        }
        return stackArray[top];
    }

    /**
     * Checks if the stack is completely empty.
     */
    public boolean isEmpty() {
        return (top == -1);
    }

    /**
     * Checks if the stack has reached its maximum capacity.
     */
    public boolean isFull() {
        return (top == maxSize - 1);
    }

    /**
     * Displays the current elements of the stack from top to bottom.
     */
    public void printStack() {
        System.out.print("Stack State (Top -> Bottom): ");
        if (isEmpty()) {
            System.out.println("Empty");
            return;
        }
        for (int i = top; i >= 0; i--) {
            System.out.print(stackArray[i] + " ");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("--- Array-Based Stack Demonstration ---");
        Main stack = new Main(5);

        stack.push(10);
        stack.push(20);
        stack.push(30);
        stack.printStack();

        System.out.println("Top element is: " + stack.peek());

        System.out.println("Popped item: " + stack.pop());
        stack.printStack();

        stack.push(40);
        stack.push(50);
        stack.push(60);
        stack.push(70); // Should trigger overflow
        stack.printStack();
    }
}

