/**
 * Complete runnable Java program implementing a dynamic Stack using a Linked List.
 * Provides dynamic growth features and safe pointer updates.
 */
public class Main {

    // Self-referential Node structure for the underlying linked chain
    static class Node {
        int data;
        Node next;

        Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    // Top of the stack is tracked by the head pointer
    private Node top = null;

    /**
     * Pushes a new element onto the dynamic stack.
     */
    public void push(int data) {
        Node newNode = new Node(data);
        newNode.next = top; // Link new node to point down to current top
        top = newNode;      // Update top pointer to the new node
        System.out.println("Pushed " + data + " onto the linked stack.");
    }

    /**
     * Pops and returns the top element from the dynamic stack.
     */
    public int pop() {
        if (isEmpty()) {
            System.out.println("Stack Underflow! Unable to pop from empty stack.");
            return -1;
        }
        int poppedData = top.data;
        top = top.next; // Advance top pointer to the next lower node
        return poppedData;
    }

    /**
     * Peeks at the top element without removing it from the chain.
     */
    public int peek() {
        if (isEmpty()) {
            System.out.println("Stack is empty! Cannot peek.");
            return -1;
        }
        return top.data;
    }

    /**
     * Checks if the stack is completely empty.
     */
    public boolean isEmpty() {
        return (top == null);
    }

    /**
     * Displays the current stack contents from top to bottom.
     */
    public void printStack() {
        System.out.print("Linked Stack State (Top -> Bottom): ");
        if (isEmpty()) {
            System.out.println("Empty");
            return;
        }
        Node temp = top;
        while (temp != null) {
            System.out.print(temp.data + " -> ");
            temp = temp.next;
        }
        System.out.println("null");
    }

    public static void main(String[] args) {
        System.out.println("--- Linked List-Based Stack Demonstration ---");
        Main stackList = new Main();

        stackList.push(100);
        stackList.push(200);
        stackList.push(300);
        stackList.printStack();

        System.out.println("Top node value: " + stackList.peek());

        System.out.println("Popped item: " + stackList.pop());
        stackList.printStack();

        stackList.push(400);
        stackList.printStack();
    }
}

