/**
 * Complete runnable Java program implementing a Simple Queue using an Array.
 * Demonstrates standard FIFO mechanics and addresses false overflow limitations.
 */
public class Main {
    private int capacity;
    private int[] queueArray;
    private int front;
    private int rear;

    // Constructor to set up the linear array queue
    public Main(int size) {
        this.capacity = size;
        this.queueArray = new int[capacity];
        this.front = -1;
        this.rear = -1;
    }

    /**
     * Enqueues a new item at the back of the queue.
     */
    public void enqueue(int item) {
        // Check for total capacity bounds
        if (rear == capacity - 1) {
            System.out.println("Queue Full Alert! Cannot enqueue " + item + " due to linear boundary limits.");
            return;
        }

        // Initialize front pointer on first insertion
        if (front == -1) {
            front = 0;
        }

        queueArray[++rear] = item;
        System.out.println("Enqueued item: " + item);
    }

    /**
     * Dequeues and returns the item from the front of the queue.
     */
    public int dequeue() {
        if (isEmpty()) {
            System.out.println("Queue Underflow! No elements available to dequeue.");
            return -1;
        }

        int removedElement = queueArray[front];
        System.out.println("Dequeued item: " + removedElement);

        // Reset queue to initial empty state if all items are removed
        if (front >= rear) {
            front = -1;
            rear = -1;
        } else {
            front++; // Move front pointer forward
        }

        return removedElement;
    }

    /**
     * Inspects the item at the front of the queue without removing it.
     */
    public int peek() {
        if (isEmpty()) {
            System.out.println("Queue is empty. Nothing to peek.");
            return -1;
        }
        return queueArray[front];
    }

    /**
     * Checks if the queue is completely empty.
     */
    public boolean isEmpty() {
        return (front == -1);
    }

    /**
     * Displays the current elements of the queue from front to rear.
     */
    public void displayQueue() {
        System.out.print("Queue Current State (Front -> Rear): ");
        if (isEmpty()) {
            System.out.println("Empty");
            return;
        }
        for (int i = front; i <= rear; i++) {
            System.out.print(queueArray[i] + " ");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("--- Simple Linear Array Queue Demonstration ---");
        Main queue = new Main(4);

        queue.enqueue(10);
        queue.enqueue(20);
        queue.enqueue(30);
        queue.enqueue(40);
        queue.displayQueue();

        queue.dequeue();
        queue.dequeue();
        queue.displayQueue();

        // Demonstrating false overflow: layout has space, but rear pointer is at its limit
        queue.enqueue(50); 
