/**
 * Complete runnable Java program implementing a Circular Queue using an Array.
 * Leverages modulo arithmetic for pointer wrapping and space reuse.
 */
public class Main {
    private int capacity;
    private int[] queueArray;
    private int front;
    private int rear;
    private int currentSize;

    // Constructor to initialize the circular ring buffer
    public Main(int size) {
        this.capacity = size;
        this.queueArray = new int[capacity];
        this.front = 0;
        this.rear = -1;
        this.currentSize = 0;
    }

    /**
     * Enqueues an item into the circular queue, wrapping indices if necessary.
     */
    public void enqueue(int item) {
        if (isFull()) {
            System.out.println("Circular Queue Full! Cannot enqueue value " + item);
            return;
        }

        // Modulo arithmetic wraps the rear index back to 0 if it reaches capacity limits
        rear = (rear + 1) % capacity;
        queueArray[rear] = item;
        currentSize++;
        System.out.println("Enqueued into ring: " + item);
    }

    /**
     * Dequeues and returns the front item, wrapping the index forward.
     */
    public int dequeue() {
        if (isEmpty()) {
            System.out.println("Circular Queue Underflow! No items available to dequeue.");
            return -1;
        }

        int removedValue = queueArray[front];
        // Modulo arithmetic wraps the front index forward smoothly
        front = (front + 1) % capacity;
        currentSize--;
        System.out.println("Dequeued from ring: " + removedValue);
        return removedValue;
    }

    /**
     * Peeks at the front item without changing queue pointers.
     */
    public int peek() {
        if (isEmpty()) {
            System.out.println("Queue is empty! Nothing to peek.");
            return -1;
        }
        return queueArray[front];
    }

    /**
     * Checks if the circular queue has filled all available slots.
     */
    public boolean isFull() {
        return (currentSize == capacity);
    }

    /**
     * Checks if the circular queue contains any active data elements.
     */
    public boolean isEmpty() {
        return (currentSize == 0);
    }

    /**
     * Displays the current state of the circular queue from front to rear.
     */
    public void displayQueue() {
        System.out.print("Circular Queue State: ");
        if (isEmpty()) {
            System.out.println("Empty");
            return;
        }
        int index = front;
        for (int i = 0; i < currentSize; i++) {
            System.out.print(queueArray[index] + " ");
            index = (index + 1) % capacity;
        }
        System.out.println(" [Size: " + currentSize + "]");
    }

    public static void main(String[] args) {
        System.out.println("--- Circular Queue Demonstration ---");
        Main circularQueue = new Main(4);

        circularQueue.enqueue(10);
        circularQueue.enqueue(20);
        circularQueue.enqueue(30);
        circularQueue.enqueue(40);
        circularQueue.displayQueue();

        circularQueue.dequeue();
        circularQueue.dequeue();
        circularQueue.displayQueue();

        // Successful wrap-around insertion into previously emptied memory slots
        circularQueue.enqueue(50);
        circularQueue.enqueue(60);
        circularQueue.displayQueue();
    }
}

