/**
 * Complete runnable Java program implementing a Priority Queue using a Max-Heap structure.
 * Elements are stored with explicit priority values and managed via heap filtering loops.
 */
public class Main {

    // Wrapper class pairing an element value with its priority ranking
    static class Task {
        int value;
        int priority;

        Task(int value, int priority) {
            this.value = value;
            this.priority = priority;
        }
    }

    private Task[] heap;
    private int size;
    private int capacity;

    public Main(int capacity) {
        this.capacity = capacity;
        this.heap = new Task[capacity];
        this.size = 0;
    }

    /**
     * Inserts a task into the priority queue, filtering it upward to maintain heap order.
     */
    public void insert(int value, int priority) {
        if (size == capacity) {
            System.out.println("Priority Queue Full! Insertion failed.");
            return;
        }

        Task newTask = new Task(value, priority);
        heap[size] = newTask;
        swim(size);
        size++;
        System.out.println("Inserted Task (Value: " + value + ", Priority: " + priority + ")");
    }

    /**
     * Extracts and returns the highest priority task, filtering the new root downward.
     */
    public Task extractMax() {
        if (size == 0) {
            System.out.println("Priority Queue Empty! Cannot extract.");
            return null;
        }

        Task maxTask = heap[0];
        heap[0] = heap[size - 1];
        heap[size - 1] = null;
        size--;

        sink(0);
        return maxTask;
    }

    // Moves an element upward to restore heap properties
    private void swim(int index) {
        while (index > 0 && heap[index].priority > heap[(index - 1) / 2].priority) {
            swap(index, (index - 1) / 2);
            index = (index - 1) / 2;
        }
    }

    // Moves an element downward to restore heap properties
    private void sink(int index) {
        while (2 * index + 1 < size) {
            int leftChild = 2 * index + 1;
            int rightChild = leftChild + 1;
            int largest = leftChild;

            if (rightChild < size && heap[rightChild].priority > heap[leftChild].priority) {
                largest = rightChild;
            }

            if (heap[index].priority >= heap[largest].priority) {
                break;
            }

            swap(index, largest);
            index = largest;
        }
    }

    private void swap(int i, int j) {
        Task temp = heap[i];
        heap[i] = heap[j];
        heap[j] = temp;
    }

    public static void main(String[] args) {
        System.out.println("--- Heap-Based Max-Priority Queue Demonstration ---");
        Main pq = new Main(10);

        pq.insert(101, 2);
        pq.insert(102, 5);
        pq.insert(103, 1);
        pq.insert(104, 8);

        System.out.println("\nExtracting elements in priority rank order:");
        while (pq.size > 0) {
            Task t = pq.extractMax();
            System.out.println("Processed Task -> Value: " + t.value + " with Priority: " + t.priority);
        }
    }
}

