     */
    public static int binarySearch(int[] sortedArray, int target) {
        int low = 0;
        int high = sortedArray.length - 1;

        // Loop runs as long as the search space contains valid elements
        while (low <= high) {
            // Safe midpoint calculation to prevent potential integer overflow
            int mid = low + (high - low) / 2;

