/**
 * Complete runnable Java program implementing an Optimized Bubble Sort.
 * Uses an early termination flag to optimize performance for nearly sorted data.
 */
public class Main {

    /**
     * Sorts an integer array using the optimized Bubble Sort algorithm.
     */
    public static void bubbleSort(int[] arr) {
        int n = arr.length;
        boolean swapped;

        // Outer loop controls the number of passes over the array
        for (int i = 0; i < n - 1; i++) {
            swapped = false; // Reset flag at the start of each pass

            // Inner loop performs adjacent comparisons, shortening as sorted elements settle
            for (int j = 0; j < n - i - 1; j++) {
                if (arr[j] > arr[j + 1]) {
                    // Swap adjacent elements that are out of order
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;

                    swapped = true; // Set flag indicating a swap occurred
                }
            }

            // Early termination: if no swaps occurred, the array is fully sorted
            if (!swapped) {
                break;
            }
        }
    }

    public static void main(String[] args) {
        System.out.println("--- Optimized Bubble Sort Demonstration ---");
        int[] array = {64, 34, 25, 12, 22, 11, 90};

        System.out.print("Unsorted Array: ");
        printArray(array);

        bubbleSort(array);

        System.out.print("Sorted Array:   ");
