/**
 * Complete runnable Java program implementing Merge Sort.
 * Demonstrates stable divide-and-conquer splitting and merging loops.
 */
public class Main {

    /**
     * Primary recursive function that coordinates the Merge Sort process.
     */
    public static void mergeSort(int[] arr, int left, int right) {
        if (left < right) {
            // Calculate the midpoint to divide the array into halves
            int mid = left + (right - left) / 2;

            // Recursively sort the left and right halves independently
            mergeSort(arr, left, mid);
            mergeSort(arr, mid + 1, right);

            // Merge the sorted halves back together
            merge(arr, left, mid, right);
        }
    }

    // Utility method to merge two sorted sub-arrays into a single sorted segment
    private static void merge(int[] arr, int left, int mid, int right) {
        // Calculate dimensions of the sub-arrays to be merged
        int n1 = mid - left + 1;
        int n2 = right - mid;

        // Allocate temporary storage buffers for the data segments
        int[] leftArray = new int[n1];
        int[] rightArray = new int[n2];

        // Copy data into the temporary left and right buffers
        for (int i = 0; i < n1; ++i) leftArray[i] = arr[left + i];
        for (int j = 0; j < n2; ++j) rightArray[j] = arr[mid + 1 + j];

        // Maintain tracking pointers for the buffers and the original array
        int i = 0, j = 0;
        int k = left;

        // Compare elements from both buffers and copy them in ascending order
        while (i < n1 && j < n2) {
            if (leftArray[i] <= rightArray[j]) {
                arr[k] = leftArray[i];
                i++;
            } else {
                arr[k] = rightArray[j];
                j++;
            }
            k++;
        }

        // Copy any remaining elements from the left buffer
        while (i < n1) {
            arr[k] = leftArray[i];
            i++;
            k++;
        }

        // Copy any remaining elements from the right buffer
        while (j < n2) {
            arr[k] = rightArray[j];
            j++;
            k++;
        }
    }

    public static void main(String[] args) {
        System.out.println("--- Merge Sort Demonstration ---");
        int[] array = {38, 27, 43, 3, 9, 82, 10};

        System.out.print("Original Dataset: ");
        printArray(array);

        mergeSort(array, 0, array.length - 1);

        System.out.print("Sorted Dataset:   ");
        printArray(array);
    }

    private static void printArray(int[] arr) {
        for (int val : arr) {
