public class Main {

    /**
     * Coordinates the Quick Sort process by recursively partitioning the dataset.
     */
    public static void quickSort(int[] arr, int low, int high) {
        if (low < high) {
            // Partition the array and retrieve the final index of the pivot element
            int pivotIndex = partition(arr, low, high);

            // Recursively sort the sub-arrays to the left and right of the pivot
            quickSort(arr, low, pivotIndex - 1);
            quickSort(arr, pivotIndex + 1, high);
        }
    }

    // Utility method to partition the array segment using the final element as the pivot
    private static int partition(int[] arr, int low, int high) {
        int pivot = arr[high]; // Select the rightmost element as the pivot
        int i = (low - 1);     // Index pointer for tracking smaller elements

        // Scan the segment and shift elements smaller than the pivot to the left
        for (int j = low; j < high; j++) {
            if (arr[j] < pivot) {
                i++;
                // Swap elements to place the smaller item on the left side
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }

        // Place the pivot element into its correct final sorted position
        int temp = arr[i + 1];
        arr[i + 1] = arr[high];
        arr[high] = temp;

        return i + 1; // Return the final index location of the pivot element
    }

