/**
 * Complete runnable Java program implementing a Binary Search Tree.
 * Demonstrates ordered insertion, element searching, and in-order display.
 */
public class Main {

    // Node class with sorted left and right child sub-tree references
    static class Node {
        int key;
        Node left, right;

        public Node(int item) {
            key = item;
            left = right = null;
        }
    }

    private Node root = null;

    /**
     * Public interface to insert a new value into the Binary Search Tree.
     */
    public void insert(int key) {
        root = insertRecursive(root, key);
    }

    // Recursive internal method to place a key based on the sorting rules
    private Node insertRecursive(Node root, int key) {
        // Base case: if the current sub-tree path is empty, spawn the new node
        if (root == null) {
            root = new Node(key);
            return root;
        }

        // Navigate left or right down the tree branches depending on value comparisons
        if (key < root.key) {
            root.left = insertRecursive(root.left, key);
        } else if (key > root.key) {
            root.right = insertRecursive(root.right, key);
        }

        return root;
    }

    /**
     * Public interface to locate a specific value within the Binary Search Tree.
     */
    public boolean search(int key) {
        return searchRecursive(root, key);
    }

    // Recursive internal method to find a key by eliminating half the path at each step
    private boolean searchRecursive(Node root, int key) {
        if (root == null) return false;
        if (root.key == key) return true;

        return key < root.key 
            ? searchRecursive(root.left, key) 
            : searchRecursive(root.right, key);
    }

    /**
     * Performs an In-Order traversal to display elements in sorted order.
     */
    public void printSorted() {
        System.out.print("Sorted Tree Elements: ");
        inOrderRecursive(root);
        System.out.println();
    }

    private void inOrderRecursive(Node root) {
