 */
public class Main {
    private int[] heap;
    private int size;
    private int capacity;

    public Main(int capacity) {
        this.capacity = capacity;
        this.size = 0;
        this.heap = new int[capacity];
    }

    /**
     * Inserts a new element into the Max-Heap.
     */
    public void insert(int value) {
        if (size == capacity) {
            System.out.println("Heap Capacity reached! Cannot insert value " + value);
            return;
        }

        // Append the new element to the end of the array
        heap[size] = value;
        // Filter the element upward to restore heap ordering properties
        swim(size);
        size++;
        System.out.println("Inserted value into heap: " + value);
    }

    /**
     * Extracts and returns the maximum element (root) from the heap.
     */
    public int extractMax() {
        if (size == 0) {
            System.out.println("Heap is empty! Extraction aborted.");
            return -1;
        }

        int maxValue = heap[0]; // Capture the maximum value at the root
        heap[0] = heap[size - 1]; // Move the last element to the root position
        size--;

        // Filter the new root downward to restore heap ordering properties
        sink(0);
        return maxValue;
    }

    // Moves an element upward to restore the Max-Heap structural rules
    private void swim(int index) {
        while (index > 0 && heap[index] > heap[(index - 1) / 2]) {
            swap(index, (index - 1) / 2); // Swap with parent node
            index = (i - 1) / 2;          // Advance pointer to parent index
        }
    }

    // Moves an element downward to restore the Max-Heap structural rules
    private void sink(int index) {
        while (2 * index + 1 < size) {
            int leftChild = 2 * index + 1;
            int rightChild = leftChild + 1;
            int largest = leftChild;

            // Determine which child node contains the larger value
            if (rightChild < size && heap[rightChild] > heap[leftChild]) {
                largest = rightChild;
            }

            // Stop filtering if the parent is larger than its largest child
            if (heap[index] >= heap[largest]) {
                break;
            }

            swap(index, largest); // Swap positions with the larger child
            index = largest;       // Advance pointer to child index
        }
    }

    private void swap(int i, int j) {
        int temp = heap[i];
        heap[i] = heap[j];
        heap[j] = temp;
    }

    /**
     * Displays the internal array layout of the heap.
     */
    public void printHeap() {
        System.out.print("Internal Array Layout: ");
        for (int i = 0; i < size; i++) {
            System.out.print(heap[i] + " ");
        }
        System.out.println();
    }

    public static void main(String[] args) {
        System.out.println("--- Max-Heap Operation Demonstration ---");
        Main maxHeap = new Main(10);

        maxHeap.insert(40);
        maxHeap.insert(15);
        maxHeap.insert(30);
        maxHeap.insert(50);
        maxHeap.insert(20);
