/**
 * Complete runnable Java program demonstrating Tree Traversal strategies.
 * Includes recursive DFS (Pre-Order, In-Order, Post-Order) and iterative BFS methods.
 */
import java.util.LinkedList;
import java.util.Queue;

public class Main {

    // Standard node structure containing left and right child links
    static class Node {
        int data;
        Node left, right;

        Node(int data) {
            this.data = data;
            this.left = this.right = null;
        }
    }

    private Node root = null;

    // 1. Pre-Order Traversal: Root -> Left -> Right
    public void printPreOrder(Node node) {
        if (node == null) return;
        System.out.print(node.data + " "); // Process parent node
        printPreOrder(node.left);          // Traverse left child
        printPreOrder(node.right);         // Traverse right child
    }

    // 2. In-Order Traversal: Left -> Root -> Right
    public void printInOrder(Node node) {
        if (node == null) return;
        printInOrder(node.left);           // Traverse left child
        System.out.print(node.data + " "); // Process parent node
        printInOrder(node.right);          // Traverse right child
    }

    // 3. Post-Order Traversal: Left -> Right -> Root
    public void printPostOrder(Node node) {
        if (node == null) return;
        printPostOrder(node.left);          // Traverse left child
        printPostOrder(node.right);         // Traverse right child
        System.out.print(node.data + " ");  // Process parent node
    }

    // 4. Level-Order Traversal (BFS): Horizontal layer processing via an auxiliary Queue
    public void printLevelOrder() {
        if (root == null) return;

        Queue<Node> queue = new LinkedList<>();
        queue.add(root);

        while (!queue.isEmpty()) {
            Node current = queue.poll();
            System.out.print(current.data + " ");

            // Enqueue left child if it exists
            if (current.left != null) queue.add(current.left);
            // Enqueue right child if it exists
            if (current.right != null) queue.add(current.right);
        }
    }

    public static void main(String[] args) {
        System.out.println("--- Tree Traversal Demonstration ---");
        Main tree = new Main();

        // Constructing a standard hierarchical binary tree
        tree.root = new Node(1);
        tree.root.left = new Node(2);
        tree.root.right = new Node(3);
        tree.root.left.left = new Node(4);
        tree.root.left.right = new Node(5);

        System.out.print("Pre-Order Path:  "); tree.printPreOrder(tree.root);  System.out.println();
        System.out.print("In-Order Path:   "); tree.printInOrder(tree.root);   System.out.println();
        System.out.print("Post-Order Path: "); tree.printPostOrder(tree.root);  System.out.println();
        System.out.print("Level-Order Path:"); tree.printLevelOrder(); System.out.println();
    }
}

