/**
 * Complete runnable Java program demonstrating Deletion inside a Binary Search Tree.
 * Implements pointer restructuring logic for leaf, single-child, and dual-child nodes.
 */
public class Main {

    // Node layout with left and right sub-tree branch pointers
    static class Node {
        int key;
        Node left, right;

        Node(int key) {
            this.key = key;
            this.left = this.right = null;
        }
    }

    private Node root = null;

    public void insert(int key) { root = insertRec(root, key); }
    private Node insertRec(Node root, int key) {
        if (root == null) return new Node(key);
        if (key < root.key) root.left = insertRec(root.left, key);
        else if (key > root.key) root.right = insertRec(root.right, key);
        return root;
    }

    /**
     * Public interface to delete a value from the Binary Search Tree.
     */
    public void delete(int key) {
        root = deleteNode(root, key);
        System.out.println("Processed deletion request for key: " + key);
    }

    // Recursive internal method to find and delete a node from the BST
    private Node deleteNode(Node root, int key) {
        // Base Case: the target key is not present in the tree branch
        if (root == null) return root;

        // Navigate down the tree paths based on value comparisons
        if (key < root.key) {
            root.left = deleteNode(root.left, key);
        } else if (key > root.key) {
            root.right = deleteNode(root.right, key);
        } 
        // Target node located, execute deletion logic
        else {
            // Cases 1 & 2: Node has no children or only a single child branch
            if (root.left == null) return root.right;
            if (root.right == null) return root.left;

            // Case 3: Node has two children. Locate and copy the in-order successor value.
            root.key = minValue(root.right);

            // Delete the duplicate in-order successor node from the right sub-tree
            root.right = deleteNode(root.right, root.key);
        }
        return root;
    }

    // Helper method to locate the smallest value in a sub-tree branch
    private int minValue(Node root) {
        int minV = root.key;
        while (root.left != null) {
            minV = root.left.key;
            root = root.left;
        }
        return minV;
    }

    public void printSorted() {
        System.out.print("Tree Layout: ");
        inOrder(root);
        System.out.println();
    }

    private void inOrder(Node node) {
        if (node != null) {
            inOrder(node.left);
            System.out.print(node.key + " ");
            inOrder(node.right);
        }
    }

    public static void main(String[] args) {
        System.out.println("--- Tree Deletion Demonstration ---");
        Main tree = new Main();

        tree.insert(50); tree.insert(30); tree.insert(20);
        tree.insert(40); tree.insert(70); tree.insert(60);

        tree.printSorted();

        tree.delete(20); // Leaf deletion
        tree.printSorted();

        tree.delete(30); // Dual-child deletion
        tree.printSorted();
    }
}

