/**
 * Complete runnable Java program demonstrating Searching within a Binary Search Tree.
 * Includes both recursive and optimized iterative lookup methods.
 */
public class Main {

    // Node structure with left and right sub-tree reference links
    static class Node {
        int data;
        Node left, right;

        Node(int data) {
            this.data = data;
            this.left = this.right = null;
        }
    }

    private Node root = null;

    public void insert(int val) { root = insertRec(root, val); }
    private Node insertRec(Node root, int val) {
        if (root == null) return new Node(val);
        if (val < root.data) root.left = insertRec(root.left, val);
        else if (val > root.data) root.right = insertRec(root.right, val);
        return root;
    }

    /**
     * Locates a target value using a recursive search strategy.
     */
    public boolean searchRecursive(Node node, int target) {
        // Base Cases: path is empty (not found) or target matches current node data
        if (node == null) return false;
        if (node.data == target) return true;

        // Navigate down the appropriate branch based on value comparisons
        return target < node.data 
            ? searchRecursive(node.left, target) 
            : searchRecursive(node.right, target);
    }

    /**
     * Locates a target value using an optimized iterative search loop.
     */
    public boolean searchIterative(int target) {
        Node current = root;
        while (current != null) {
            if (target == current.data) {
                return true; // Target element found
            }
            // Advance the tracking pointer down the left or right branch
            current = target < current.data ? current.left : current.right;
        }
        return false; // Target element not present in the tree structure
    }

    public static void main(String[] args) {
        System.out.println("--- Tree Searching Demonstration ---");
        Main bst = new Main();

        bst.insert(45);
        bst.insert(25);
        bst.insert(65);
        bst.insert(15);
        bst.insert(35);

        int searchKey = 35;
        System.out.println("Recursive Lookup for " + searchKey + ": " + bst.searchRecursive(bst.root, searchKey));
        System.out.println("Iterative Lookup for " + searchKey + ": " + bst.searchIterative(searchKey));
        System.out.println("Iterative Lookup for 99: " + bst.searchIterative(99));
    }
}
